SELECT Directed_by, COUNT(*) AS NumberOfCartoons
FROM Cartoon
GROUP BY Directed_by;

SELECT Directed_by, COUNT(*) AS Cartoon_Count
FROM Cartoon
GROUP BY Directed_by;

